class Solution:
    def validPalindrome(self, s):
        def is_pal(t):
            return t == t[::-1]
        if is_pal(s):
            return True
        i, j = 0, len(s) - 1
        while i < j:
            if s[i] != s[j]:
                return is_pal(s[i + 1:j + 1]) or is_pal(s[i:j])
            i += 1
            j -= 1
        return True

