class Solution:
    def validPalindrome(self, s):
        def pal(lo, hi):
            while lo < hi:
                if s[lo] != s[hi]:
                    return False
                lo += 1
                hi -= 1
            return True
        i, j = 0, len(s) - 1
        while i < j:
            if s[i] != s[j]:
                return pal(i + 1, j) or pal(i, j - 1)
            i += 1
            j -= 1
        return True

