var validPalindrome = function(s) {
    const pal = (lo, hi) => {
        while (lo < hi) {
            if (s[lo] !== s[hi]) return false;
            lo++;
            hi--;
        }
        return true;
    };
    let i = 0, j = s.length - 1;
    while (i < j) {
        if (s[i] !== s[j]) return pal(i + 1, j) || pal(i, j - 1);
        i++;
        j--;
    }
    return true;
};
